// // This module implements a 4-bit BCD counter that decrements by 1 on every positive clock edge and resets to 9 when the reset signal is high. It underflows to 9 after reaching 0.
module bcd_counter(
	input clk,
	input rst,
	output reg [3:0] q);
always @(posedge clk or posedge rst) begin
		if (rst)
			q <= 4'b0000;
		else if (q == 4'b1001)
			q <= 4'b0000;
		else
			q <= q + 1;
	end
endmodule
